import React from 'react';
import './App.css';

function App() {
  const items = [
    { id: 1, title: "Kart 1" },
    { id: 2, title: "Kart 2" }
  ];

  return (
    <div className="App">
      <header className="App-header">
        <h1>Projem Başarıyla Çalışıyor!</h1>
      </header>

      <div className="card-container">
        {items.map((item) => (
          <div key={item.id} className="card">
            <div className="card-body">
              <div>{item.title}</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default App;
